public int[] fix45(int[] nums) {
    int i = 0, j = 1;
    while (j < nums.length) {
        if (nums[i] == 4 && nums[j] == 5) {
            i++;
            j++;
        } else if (nums[i] == 4 && nums[j] != 5) {
            swap(nums, i, j);
            j++;
        } else {
            i++;
        }
    }
    return nums;
}

private void swap(int[] nums, int i, int j) {
    int temp = nums[i];
    nums[i] = nums[j];
    nums[j] = temp;
}

public int[] fix45(int[] nums) {
    int n = nums.length;
    int left = 0, right = 0;

    while (right < n) {
        if (nums[right] == 5) {
            while (left < right && nums[left] != 4) {
                left++;
            }

            if (left == right) {
                int temp = nums[right];
                nums[right] = nums[right + 1];
                nums[right + 1] = temp;
                right++;
            } else {
                left++;
                right++;
            }
        } else {
            right++;
        }
    }

    return nums;
}

